const data = $input.first().json;

const summary = `LOAN PORTFOLIO RISK METRICS: Total Active Loans: ${data.total_active_loans}, Bad Loan Percentage: ${data.bad_loan_percentage}%, High Risk Grade Percentage (D/E/F/G): ${data.high_risk_grade_percentage}%, Avg Interest Rate: A=${data.avg_rate_grade_a}%, B=${data.avg_rate_grade_b}%, C=${data.avg_rate_grade_c}%, D=${data.avg_rate_grade_d}%, E=${data.avg_rate_grade_e}%, F=${data.avg_rate_grade_f}%, G=${data.avg_rate_grade_g}%, Region Default %: Cannught=${data.default_pct_cannught}%, Leinster=${data.default_pct_leinster}%, Munster=${data.default_pct_munster}%, N.IRL=${data.default_pct_northern_irl}%, Ulster=${data.default_pct_ulster}%`;

return [{
  json: {
    model: "llama-3.3-70b-versatile",
    messages: [
      {"role": "system", "content": "You are a senior loan risk analyst. Analyze portfolio metrics and summarize risk exposure, red flags and actionable insights."},
      {"role": "user", "content": summary}
    ]
  }
}];
